class Solution:
    def shortestToChar(self, s, c):
        n = len(s)
        INF = n
        ans = [INF] * n
        prev = -INF
        for i in range(n):
            if s[i] == c:
                prev = i
            ans[i] = i - prev
        prev = 2 * INF
        for i in range(n - 1, -1, -1):
            if s[i] == c:
                prev = i
            ans[i] = min(ans[i], prev - i)
        return ans

