var shortestToChar = function(s, c) {
    const n = s.length;
    const INF = n;
    const ans = new Array(n).fill(INF);
    let prev = -INF;
    for (let i = 0; i < n; i++) {
        if (s[i] === c) prev = i;
        ans[i] = i - prev;
    }
    prev = 2 * INF;
    for (let i = n - 1; i >= 0; i--) {
        if (s[i] === c) prev = i;
        ans[i] = Math.min(ans[i], prev - i);
    }
    return ans;
};
